use aya_ebpf::{helpers::bpf_loop, programs::Context};

struct LoopContext<'a> {
    ctx: &'a XdpContext,
    // Whatever data you want. In my case, a reference to a map value with an array. Example:
    data: &'a [u16; 256],
}

unsafe fn loop_body(index: u64, data: *mut c_void) -> i64 {
    // Make the verifier happy as it manages to track the array is from a map value.
    if index >= 256 { return 1 }

    let ctx = data as *mut LoopContext;
    let item = (*ctx).data[index as usize];

    // Do something with the item, e.g. match on part of the packet from ctx.
}

// And in the main xdp program:
if let Some(data) = MAP.get(/* stuff */) {
    let mut ctx = LoopContext { ctx: &ctx, data };
    let fn_ptr = loop_body as *mut fn(u64, *mut c_void) -> i64 as *mut c_void;
    let ctx_ptr = &mut ctx as *mut LoopContext as *mut c_void;
    // The real thing loads the iter count from the map, but it's for demonstration purposes.
    bpf_loop(256, fn_ptr, ctx_ptr, 0);
}
